window.__DATA_WEEKS = {"weeks": [{"week": 0, "title": "Ankunft", "intro": "Dein erster Tag in Greifshafen. Die Umzugskartons stehen noch im Flur. Draußen ist es grau. Du lädst die Streem-App.", "unlock": []}, {"week": 1, "title": "Erste Woche Schule", "intro": "Neue Schule, neue Gesichter. Du hörst, dass alle auf Streem sind. Die Plattform schlägt dir Profile vor.", "unlock": []}, {"week": 2, "title": "Kennenlernen", "intro": "Ein paar aus deiner neuen Klasse folgen dir zurück. Der Feed sortiert sich langsam ein.", "unlock": []}, {"week": 3, "title": "Einzelner Song", "intro": "Ein Song aus deiner Playlist geht in deinem Viertel gerade viral. Mehrere Leute posten dazu.", "unlock": []}, {"week": 4, "title": "Halbzeit Tag 1", "intro": "Vier Wochen bist du jetzt online. Die App fühlt sich schon vertrauter an. Zeit für eine kurze Reflexion.", "unlock": ["reflection_half1"]}, {"week": 5, "title": "Erste Politik-Posts", "intro": "Im Feed taucht erstmals Politisches auf — noch harmlos, eine Demo, ein Kommentar, ein Meme.", "unlock": []}, {"week": 6, "title": "Wissenschaft vs. Gefühl", "intro": "Eine Studie macht die Runde. In deinem Feed kursieren drei Versionen davon — je nach Absender ganz anders erzählt.", "unlock": []}, {"week": 7, "title": "Du postest selbst", "intro": "Du traust dich erstmals, selbst etwas zu schreiben. Die App schlägt dir dazu Hashtags vor.", "unlock": []}, {"week": 8, "title": "Erster Streit", "intro": "Unter einem deiner Kommentare zofft sich eine fremde Person mit einem Bot-Account.", "unlock": []}, {"week": 9, "title": "Anzeigen", "intro": "Plötzlich tauchen gekennzeichnete Anzeigen in deinem Feed auf. Manche passen erstaunlich gut.", "unlock": ["ads", "algorithm_panel"]}, {"week": 10, "title": "Gaming-Gilde", "intro": "Eine Einladung zu einer Streem-Gilde („Gaming Nord“) landet in deiner Inbox.", "unlock": ["discord"]}, {"week": 11, "title": "Empörungs-Welle", "intro": "Ein Politiker hat etwas gesagt. Oder vielleicht auch nicht. Dein Feed ist voll davon.", "unlock": []}, {"week": 12, "title": "Follow-Zuwachs", "intro": "Dir folgen plötzlich einige Accounts, die du nicht kennst. Manche wirken… seltsam.", "unlock": ["bots"]}, {"week": 13, "title": "Ein Influencer antwortet", "intro": "Ein größerer Account reagiert auf einen deiner Posts. Deine Reichweite wächst.", "unlock": []}, {"week": 14, "title": "Shitstorm oder Ruhm?", "intro": "Einer deiner Posts geht überraschend viral — je nach Inhalt: positiv oder nicht.", "unlock": ["shitstorm"]}, {"week": 15, "title": "Rabbit Hole spürbar?", "intro": "Unter „Dir könnte auch gefallen“ tauchen Inhalte auf, die du weder gesucht noch gewollt hast.", "unlock": ["recommendation_panel"]}, {"week": 16, "title": "Deepfake im Umlauf", "intro": "Ein Video einer lokalen Politikerin kursiert. Echt? Gefälscht? Dein Feed ist sich sicher — nur ist er nicht einig.", "unlock": []}, {"week": 17, "title": "Einladung in radikalere Gilde", "intro": "Eine neue Gilden-Einladung — diesmal mit klarerer Agenda.", "unlock": []}, {"week": 18, "title": "Zwischenreflexion", "intro": "Zeit für einen kurzen Blick auf das, was bisher war.", "unlock": ["reflection_mid"]}, {"week": 19, "title": "Wahlkampf beginnt", "intro": "In Greifshafen wird in drei Wochen gewählt. Vier Parteien, ein Feed, vier Wahrheiten.", "unlock": ["election_campaign"]}, {"week": 20, "title": "Wahlkampf-Mitte", "intro": "Dein Feed zeigt dir, wer angeblich führt — aber nur wer: je nachdem, was du geliked hast.", "unlock": []}, {"week": 21, "title": "Debatten-Abend", "intro": "Eine TV-Debatte wird auf Streem live kommentiert. Die Clips, die trenden, sind — natürlich — die lautesten.", "unlock": []}, {"week": 22, "title": "Wahl", "intro": "Die Greifshafener Kommunalwahl steht an. Wen hätte dein Feed dich wählen lassen?", "unlock": ["election"]}, {"week": 23, "title": "Nachspiel", "intro": "Nach der Wahl: Sieger, Verlierer, Empörung. Der Algorithmus macht, was er am besten kann — die lautesten oben halten.", "unlock": []}, {"week": 24, "title": "Hate-Speech-Incident", "intro": "In einer Gilde eskaliert ein Gespräch. Jemand wird beleidigt. Was tust du?", "unlock": []}, {"week": 25, "title": "Stille Stunde", "intro": "Du nimmst dir vor, weniger zu scrollen. Der Feed reagiert — mit immer größerem Köder.", "unlock": []}, {"week": 26, "title": "Jahresrückblick", "intro": "Streem hat deinen Jahresrückblick fertig. Willst du sehen, was der Algorithmus über dich gelernt hat?", "unlock": ["wrapped", "sandbox", "manifest"]}]};
